                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  <div className="bg-white border border-[#141414] p-3">
                    <p className="text-[12px] font-black uppercase tracking-widest text-[#4B4B4B] mb-1">Điểm mạnh</p>
