'use client'

import React, { useState, useDeferredValue, useMemo } from 'react'
import Link from 'next/link'
import SentenceScramble from '@/components/study/SentenceScramble'
import { CEFR_LEVELS, normalizeCefrLevel } from '@/lib/levels'
import { 
  Search, 
  Compass, 
  Play, 
  ChevronDown, 
  X,
  BookOpen,
  Gamepad2,
  Brain,
  Loader2
} from 'lucide-react'

interface GrammarPoint {
  id: string
  slug: string
  title: string
  level: string
  explanation: string
  structure: string | null
  example: string | null
  exampleSentence: string | null
  exerciseData: string[] | null
  topic: { name: string } | null
}

const levelColors: Record<string, string> = {
  A1: 'bg-blue-600 text-white',
  A2: 'bg-green-600 text-white',
  B1: 'bg-red-600 text-white',
  B2: 'bg-orange-600 text-white',
  C1: 'bg-purple-700 text-white',
  C2: 'bg-black text-white',
}

export default function GrammarLibrary({ initialPoints }: { initialPoints: any[] }) {
  const [search, setSearch] = useState('')
  const [activeLevel, setActiveLevel] = useState('All')
  const [practicingId, setPracticingId] = useState<string | null>(null)
  const [visibleCount, setVisibleCount] = useState(12) 
  const deferredSearch = useDeferredValue(search)

  const levels = ['All', ...CEFR_LEVELS]

  const filteredPoints = useMemo(() => {
    return initialPoints.filter(p => {
      const matchesSearch =
        p.title.toLowerCase().includes(deferredSearch.toLowerCase()) ||
        (p.structure && p.structure.toLowerCase().includes(deferredSearch.toLowerCase()))
      const matchesLevel = activeLevel === 'All' || normalizeCefrLevel(p.level) === activeLevel
      return matchesSearch && matchesLevel
    })
  }, [deferredSearch, activeLevel, initialPoints])

  const practicingPoint = practicingId ? initialPoints.find(p => p.id === practicingId) : null

  const practicesentences: string[] = practicingPoint?.exerciseData ?? 
    (practicingPoint?.example ? [practicingPoint.example] : ['I am learning English'])

  const [sentenceIndex, setSentenceIndex] = useState(0)
  const currentSentence = practicesentences[sentenceIndex % practicesentences.length]

  const handlePracticeSuccess = () => {
    if (sentenceIndex < practicesentences.length - 1) {
      setSentenceIndex(prev => prev + 1)
    }
  }

  const handleOpenPractice = (id: string) => {
    setSentenceIndex(0)
    setPracticingId(id)
  }

  const loadMore = () => setVisibleCount(prev => prev + 12)

  return (
    <div className="space-y-12">
      {/* Search + Level Filter */}
      <div className="flex flex-col lg:flex-row gap-6 items-center">
        <div className="relative w-full lg:w-[400px]">
          <Search className="absolute left-5 top-1/2 -translate-y-1/2 text-newsprint-black" size={20} strokeWidth={3} />
          <input
            type="text"
            placeholder="Tìm kiếm ngữ pháp..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-14 pr-6 py-4 bg-white border-[3px] border-newsprint-black shadow-brutalist-soft focus:outline-none font-sans font-black uppercase text-xs tracking-widest placeholder:text-newsprint-gray"
          />
        </div>
        <div className="flex items-center gap-3 p-1 bg-[#E5E7EB] border-[3px] border-newsprint-black overflow-x-auto no-scrollbar">
          {levels.map(l => (
            <button
              key={l}
              onClick={() => {
                setActiveLevel(l)
                setVisibleCount(12)
              }}
              className={`px-6 py-3 font-sans font-black text-[10px] uppercase tracking-widest transition-all whitespace-nowrap border-[2px] ${
                activeLevel === l 
                  ? 'bg-newsprint-black text-white border-newsprint-black' 
                  : 'text-newsprint-black border-transparent hover:bg-white'
              }`}
            >
              {l}
            </button>
          ))}
        </div>
      </div>

      <p className="text-[10px] font-sans font-black text-newsprint-gray-dark px-2 uppercase tracking-widest">
        Hiển thị <span className="text-red-600">{Math.min(visibleCount, filteredPoints.length)}</span> / {filteredPoints.length} chủ điểm {activeLevel !== 'All' ? activeLevel : ''}
      </p>

      {/* Cards Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {filteredPoints.length > 0 ? filteredPoints.slice(0, visibleCount).map((gp) => (
          <div
            key={gp.id}
            className="group bg-white border-[3px] border-newsprint-black shadow-brutalist-card p-8 flex flex-col gap-6 hover:-translate-y-1 transition-all hover:shadow-brutalist-heavy"
          >
            {/* Card Header */}
            <div className="flex items-start justify-between gap-3">
              <span className={`px-3 py-1 font-sans font-black text-[9px] uppercase tracking-widest border-[2px] border-newsprint-black ${levelColors[normalizeCefrLevel(gp.level)] || 'bg-newsprint-gray text-white'}`}>
                {normalizeCefrLevel(gp.level)}
              </span>
              <div className="w-10 h-10 bg-newsprint-paper border-[3px] border-newsprint-black flex items-center justify-center shadow-brutalist-soft group-hover:rotate-6 transition-transform">
                <Compass size={20} strokeWidth={3} />
              </div>
            </div>

            {/* Title + Structure */}
            <div className="space-y-4">
              <h3 className="text-2xl font-serif font-black text-newsprint-black leading-tight uppercase group-hover:text-red-600 transition-colors">
                {gp.title}
              </h3>

              {gp.structure ? (
                <div className="inline-flex items-center gap-3 bg-newsprint-paper border-[2px] border-newsprint-black px-4 py-2">
                  <span className="text-[9px] font-sans font-black text-newsprint-gray-dark uppercase tracking-widest">CT</span>
                  <code className="text-xs font-black text-newsprint-black">{gp.structure}</code>
                </div>
              ) : (
                <p className="text-xs text-newsprint-gray-dark font-sans font-bold leading-relaxed line-clamp-2 uppercase tracking-tight">{gp.explanation}</p>
              )}
            </div>

            {/* Actions */}
            <div className="mt-auto grid grid-cols-2 gap-4 pt-6 border-t-[2px] border-newsprint-black/10">
              <Link
                href={`/dashboard/grammar/${gp.slug}`}
                className="py-3 bg-white border-[2px] border-newsprint-black text-center text-[10px] font-sans font-black text-newsprint-black uppercase tracking-widest hover:bg-newsprint-paper transition-all flex items-center justify-center gap-2"
              >
                <BookOpen size={14} strokeWidth={3} /> BÀI HỌC
              </Link>
              <button
                onClick={() => handleOpenPractice(gp.id)}
                disabled={!gp.example && !gp.exerciseData}
                className={`py-3 border-[2px] border-newsprint-black text-center text-[10px] font-sans font-black uppercase tracking-widest transition-all flex items-center justify-center gap-2 ${
                  gp.example || gp.exerciseData
                    ? 'bg-newsprint-black text-white hover:bg-red-600'
                    : 'bg-newsprint-gray-light text-newsprint-gray-dark cursor-not-allowed opacity-50'
                }`}
              >
                <Gamepad2 size={14} strokeWidth={3} /> LUYỆN TẬP
              </button>
            </div>
          </div>
        )) : (
          <div className="col-span-full py-20 text-center space-y-8 bg-newsprint-paper border-[3px] border-dashed border-newsprint-black">
            <div className="relative w-32 h-32 mx-auto">
              <div className="absolute inset-0 bg-red-600/10 rounded-full blur-2xl animate-pulse" />
              <div className="relative w-full h-full bg-white border-[3px] border-newsprint-black shadow-brutalist-soft flex items-center justify-center text-newsprint-black font-black">
                <Search size={48} strokeWidth={3} />
              </div>
            </div>
            <div className="space-y-4">
              <h3 className="text-3xl font-serif font-black text-newsprint-black uppercase">Trống trơn...</h3>
              <p className="text-[11px] font-sans font-bold text-newsprint-gray-dark uppercase tracking-widest max-w-sm mx-auto">Chúng tôi không tìm thấy chủ điểm này trong thư viện chính thức.</p>
            </div>
            <button className="px-10 py-5 bg-red-600 text-white font-sans font-black uppercase tracking-widest text-sm border-[3px] border-newsprint-black shadow-brutalist-soft hover:translate-y-1 hover:shadow-none transition-all flex items-center gap-3 mx-auto">
              <Brain size={20} strokeWidth={3} /> TẠO VỚI AI
            </button>
          </div>
        )}
      </div>

      {/* Load More Button */}
      {visibleCount < filteredPoints.length && (
        <div className="flex justify-center pt-8">
          <button 
            onClick={loadMore}
            className="px-10 py-5 bg-white border-[3px] border-newsprint-black font-sans font-black text-newsprint-black uppercase tracking-widest text-sm shadow-brutalist-card hover:bg-newsprint-paper active:translate-y-1 transition-all flex items-center gap-3"
          >
            XEM THÊM <ChevronDown size={18} strokeWidth={3} />
          </button>
        </div>
      )}

      {/* Practice Modal Overlay */}
      {practicingPoint && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-newsprint-black/70 backdrop-blur-sm" onClick={() => setPracticingId(null)} />
          <div className="relative w-full max-w-2xl">
            {/* Close */}
            <button
              onClick={() => setPracticingId(null)}
              className="absolute -top-4 -right-4 z-[60] w-12 h-12 bg-white border-[3px] border-newsprint-black shadow-brutalist-soft flex items-center justify-center font-black text-newsprint-black hover:bg-red-600 hover:text-white transition-all"
            ><X size={24} strokeWidth={4} /></button>

            {/* Context header */}
            <div className="mb-6 bg-white border-[3px] border-newsprint-black p-6 shadow-brutalist-card text-center relative z-10">
              <span className={`px-4 py-1 font-sans font-black text-[10px] uppercase tracking-widest border-[2px] border-newsprint-black mb-4 inline-block ${levelColors[normalizeCefrLevel(practicingPoint.level)] || ''}`}>
                {normalizeCefrLevel(practicingPoint.level)}
              </span>
              <h4 className="font-serif font-black text-newsprint-black text-2xl uppercase">{practicingPoint.title}</h4>
              {practicingPoint.structure && (
                <code className="text-sm font-black text-red-600 bg-newsprint-paper border-[2px] border-newsprint-black px-4 py-1 mt-3 inline-block">{practicingPoint.structure}</code>
              )}
              {(practicesentences.length > 1) && (
                <p className="text-[10px] text-newsprint-gray-dark mt-4 font-black uppercase tracking-[0.2em]">Tiến độ: {sentenceIndex + 1} / {practicesentences.length}</p>
              )}
            </div>

            <SentenceScramble
              sentence={currentSentence}
              translation={practicingPoint.exampleSentence || ""}
              onSuccess={handlePracticeSuccess}
            />
          </div>
        </div>
      )}
    </div>
  )
}

'use client'

import React, { useState, useEffect, useRef } from 'react'
import { Search, Bell } from 'lucide-react'
import Link from 'next/link'
import { formatCefrLevel } from '@/lib/levels'

interface HeaderProps {
  user: {
    email?: string | null
    user_metadata?: {
      full_name?: string | null
      avatar_url?: string | null
    } | null
  } | null
  dbUser?: {
    name?: string | null
    image?: string | null
    proficiencyLevel?: string | null
  } | null
  wordsToday?: number
}

type NotificationItem = {
  id: string
  type: string
  title: string
  message: string
  createdAt: string
  readAt: string | null
}

function formatNotificationTime(value: string): string {
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return '--'
  return new Intl.DateTimeFormat('vi-VN', {
    timeZone: 'Asia/Ho_Chi_Minh',
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
  }).format(date)
}

function getVNHour(): number {
  return parseInt(
    new Date().toLocaleString('en-US', {
      timeZone: 'Asia/Ho_Chi_Minh',
      hour: 'numeric',
      hour12: false,
    }),
    10
  )
}

function getGreeting(hour: number): { text: string } {
  if (hour >= 5 && hour < 12)  return { text: 'Chào buổi sáng' }
  if (hour >= 12 && hour < 18) return { text: 'Chào buổi chiều' }
  if (hour >= 18 && hour < 22) return { text: 'Chào buổi tối' }
  return { text: 'Chào đêm khuya' }
}

export default function Header({ user, dbUser, wordsToday = 0 }: HeaderProps) {
  const [greeting, setGreeting] = useState(() => getGreeting(getVNHour()))
  const [isNotifOpen, setIsNotifOpen] = useState(false)
  const [notifLoading, setNotifLoading] = useState(false)
  const [notifPage, setNotifPage] = useState(1)
  const [notifTotalPages, setNotifTotalPages] = useState(1)
  const [unreadCount, setUnreadCount] = useState(0)
  const [notifications, setNotifications] = useState<NotificationItem[]>([])
  const notifPanelRef = useRef<HTMLDivElement | null>(null)

  useEffect(() => {
    const update = () => setGreeting(getGreeting(getVNHour()))
    const msToNextMinute = (60 - new Date().getSeconds()) * 1000
    const t = setTimeout(() => {
      update()
      const iv = setInterval(update, 60_000)
      return () => clearInterval(iv)
    }, msToNextMinute)
    return () => clearTimeout(t)
  }, [])

  useEffect(() => {
    const onClickOutside = (event: MouseEvent) => {
      if (!notifPanelRef.current) return
      if (notifPanelRef.current.contains(event.target as Node)) return
      setIsNotifOpen(false)
    }

    document.addEventListener('mousedown', onClickOutside)
    return () => document.removeEventListener('mousedown', onClickOutside)
  }, [])

  const fetchNotifications = async (page: number, shouldMarkRead = false) => {
    setNotifLoading(true)
    try {
      const res = await fetch(`/api/notifications?page=${page}&pageSize=8`, { cache: 'no-store' })
      const data = (await res.json()) as {
        ok?: boolean
        items?: NotificationItem[]
        page?: number
        totalPages?: number
        unreadCount?: number
      }

      if (!res.ok || !data.ok) return

      setNotifications(data.items || [])
      setNotifPage(data.page || page)
      setNotifTotalPages(data.totalPages || 1)
      setUnreadCount(data.unreadCount || 0)

      if (shouldMarkRead && (data.unreadCount || 0) > 0) {
        await fetch('/api/notifications', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'mark_read_all' }),
        })
        setUnreadCount(0)
      }
    } catch {
      // Silent fallback for header UX
    } finally {
      setNotifLoading(false)
    }
  }

  useEffect(() => {
    const t = setTimeout(() => {
      void fetchNotifications(1)
    }, 0)
    const iv = setInterval(() => {
      void fetchNotifications(1)
    }, 60_000)
    return () => {
      clearTimeout(t)
      clearInterval(iv)
    }
  }, [])

  const displayName = dbUser?.name
    || user?.user_metadata?.full_name
    || user?.email?.split('@')[0]
    || 'Học viên'

  const avatarUrl = dbUser?.image || user?.user_metadata?.avatar_url || null

  const nameParts = displayName.split(' ').filter(Boolean)
  const initials = nameParts.length >= 2
    ? (nameParts[0][0] + nameParts[1][0]).toUpperCase()
    : displayName.slice(0, 2).toUpperCase()

  const levelLabel = formatCefrLevel(dbUser?.proficiencyLevel, true)

  return (
    <div
      style={{
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'space-between',
        gap: 16,
        width: '100%',
        minWidth: 0,
      }}
    >
      {/* ── Left: Greeting ── */}
      <div style={{ minWidth: 0, flex: '1 1 auto' }}>
        <h2
          className="font-serif font-black text-[#141414] vietnamese-text"
          style={{
            fontSize: 'clamp(18px, 2.5vw, 24px)',
            lineHeight: 1.2,
            whiteSpace: 'nowrap',
            overflow: 'hidden',
            textOverflow: 'ellipsis',
          }}
        >
          {greeting.text}, {displayName}!
        </h2>
        <p 
          className="vietnamese-text"
          style={{ 
            fontSize: 11, 
            color: wordsToday >= 10 ? '#dc2626' : '#4B4B4B', 
            fontWeight: 800, 
            marginTop: 4, 
            textTransform: 'uppercase', 
            letterSpacing: '0.05em' 
          }}
        >
          {wordsToday >= 10 
            ? `★ Mục tiêu đã hoàn thành (${wordsToday} từ)!` 
            : `Mục tiêu hôm nay: ${wordsToday}/10 từ mới.`}
        </p>
      </div>

      {/* ── Right: Search + Bell + User ── */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 10, flexShrink: 0 }}>

        {/* Search */}
        <div style={{ position: 'relative' }} className="hidden md:block">
          <Search
            size={13}
            strokeWidth={1.75}
            style={{
              position: 'absolute',
              left: 10,
              top: '50%',
              transform: 'translateY(-50%)',
              color: '#4B4B4B',
              pointerEvents: 'none',
            }}
          />
          <input
            type="text"
            placeholder="Tìm bài học, từ vựng..."
            style={{
              height: 36,
              width: 200,
              paddingLeft: 30,
              paddingRight: 12,
              border: '2px solid #141414',
              background: 'rgba(255,255,255,0.7)',
              fontSize: 11,
              color: '#141414',
              outline: 'none',
            }}
            className="focus:border-[#141414] transition-colors"
          />
        </div>

        {/* Bell + Notification panel */}
        <div ref={notifPanelRef} style={{ position: 'relative' }}>
          <button
            onClick={() => {
              const nextOpen = !isNotifOpen
              setIsNotifOpen(nextOpen)
              if (nextOpen) void fetchNotifications(1, true)
            }}
            style={{
              width: 36,
              height: 36,
              border: '2px solid #141414',
              background: 'rgba(255,255,255,0.7)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#141414',
              cursor: 'pointer',
              position: 'relative',
            }}
            className="hover:bg-white hover:shadow-[4px_4px_0px_0px_rgba(20,20,20,1)] hover:-translate-y-0.5 transition-all outline-none"
          >
            <Bell size={14} strokeWidth={2.5} />
            {unreadCount > 0 ? (
              <span className="absolute -top-2 -right-2 min-w-[18px] h-[18px] px-1 rounded-full bg-[#B91C1C] border border-[#141414] text-white text-[9px] font-black leading-[16px] text-center">
                {unreadCount > 99 ? '99+' : unreadCount}
              </span>
            ) : null}
          </button>

          {isNotifOpen ? (
            <div className="absolute right-0 top-[44px] z-50 w-[360px] max-w-[88vw] border-[3px] border-[#141414] bg-[#F5F0E8] shadow-[10px_10px_0px_0px_rgba(20,20,20,1)]">
              <div className="flex items-center justify-between border-b-[2px] border-[#141414] px-3 py-2">
                <p className="text-[10px] font-black uppercase tracking-[0.14em] text-[#141414]">Thông báo</p>
                <button
                  onClick={() => void fetchNotifications(notifPage)}
                  className="border border-[#141414] bg-white px-2 py-0.5 text-[9px] font-black uppercase tracking-[0.12em] hover:bg-[#141414] hover:text-white"
                >
                  Làm mới
                </button>
              </div>

              <div className="max-h-[320px] overflow-y-auto p-2 space-y-2">
                {notifLoading ? <p className="px-2 py-3 text-xs font-semibold text-[#4B4B4B]">Đang tải...</p> : null}
                {!notifLoading && notifications.length === 0 ? (
                  <p className="px-2 py-3 text-xs font-semibold text-[#4B4B4B]">Chưa có thông báo nào.</p>
                ) : null}
                {notifications.map((item) => (
                  <div key={item.id} className="border border-[#141414] bg-white p-2">
                    <p className="text-[11px] font-black text-[#141414]">{item.title}</p>
                    <p className="mt-1 text-[11px] text-[#333]">{item.message}</p>
                    <p className="mt-1 text-[10px] font-semibold text-[#4B4B4B]">{formatNotificationTime(item.createdAt)}</p>
                  </div>
                ))}
              </div>

              <div className="flex items-center justify-between border-t-[2px] border-[#141414] px-3 py-2">
                <button
                  disabled={notifPage <= 1 || notifLoading}
                  onClick={() => void fetchNotifications(notifPage - 1)}
                  className="border border-[#141414] bg-white px-2 py-1 text-[10px] font-black uppercase tracking-[0.12em] disabled:opacity-40 disabled:cursor-not-allowed hover:bg-[#141414] hover:text-white"
                >
                  Trước
                </button>
                <span className="text-[10px] font-black uppercase tracking-[0.12em] text-[#141414]">
                  Trang {notifPage}/{notifTotalPages}
                </span>
                <button
                  disabled={notifPage >= notifTotalPages || notifLoading}
                  onClick={() => void fetchNotifications(notifPage + 1)}
                  className="border border-[#141414] bg-white px-2 py-1 text-[10px] font-black uppercase tracking-[0.12em] disabled:opacity-40 disabled:cursor-not-allowed hover:bg-[#141414] hover:text-white"
                >
                  Sau
                </button>
              </div>
            </div>
          ) : null}
        </div>

        {/* User chip */}
        <Link
          href="/dashboard/settings"
          style={{
            display: 'flex',
            alignItems: 'center',
            border: '2px solid #141414',
            background: 'rgba(255,255,255,0.7)',
            textDecoration: 'none',
          }}
          className="w-9 h-9 sm:w-auto sm:h-auto justify-center sm:justify-start gap-0 sm:gap-2 sm:pr-3 hover:bg-white hover:shadow-[4px_4px_0px_0px_rgba(20,20,20,1)] hover:-translate-y-0.5 transition-all"
        >
          <div
            style={{
              width: 36,
              height: 36,
              background: '#141414',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              flexShrink: 0,
            }}
          >
            {avatarUrl ? (
              <img src={avatarUrl} alt="Avatar" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
            ) : (
              <span style={{ fontSize: 11, fontWeight: 900, color: '#fff', letterSpacing: '0.05em' }}>
                {initials}
              </span>
            )}
          </div>
          <div className="hidden sm:flex flex-col">
            <span
              className="vietnamese-text"
              style={{ fontSize: 11, fontWeight: 800, color: '#141414', lineHeight: 1 }}
            >
              {displayName}
            </span>
            <span style={{ fontSize: 9, color: '#4B4B4B', fontWeight: 800, letterSpacing: '0.15em', textTransform: 'uppercase', marginTop: 2 }}>
              {levelLabel}
            </span>
          </div>
        </Link>
      </div>
    </div>
  )
}

'use client'

import React, { useState } from 'react'
import Link from 'next/link'
import { usePathname } from 'next/navigation'
import { signOut } from '@/app/actions/auth'
import ConfirmDialog from '@/components/ui/ConfirmDialog'
import { motion } from 'framer-motion'
import {
  LayoutDashboard,
  CreditCard,
  Bot,
  TrendingUp,
  UserCircle,
  ReceiptText,
  LogOut,
  PanelLeftClose,
  PanelLeftOpen,
  Crown,
} from 'lucide-react'

type SidebarDbUser = {
  isPro?: boolean
  proType?: '3_MONTHS' | '6_MONTHS' | '1_YEAR' | null
}

type SidebarProps = {
  user: unknown
  dbUser: SidebarDbUser | null
  collapsed?: boolean
  onToggle?: () => void
}

const menuItems = [
  { name: 'Tổng quan', icon: LayoutDashboard, path: '/dashboard' },
  { name: 'Flashcard', icon: CreditCard, path: '/dashboard/flashcards' },
  { name: 'AI Tutor', icon: Bot, path: '/dashboard/ai-chat' },
  { name: 'Tiến độ', icon: TrendingUp, path: '/dashboard/progress' },
  { name: 'Lịch sử thanh toán', icon: ReceiptText, path: '/dashboard/payments/history' },
  { name: 'Tài khoản', icon: UserCircle, path: '/dashboard/settings' },
]

function getPlanLabel(proType: SidebarDbUser['proType']) {
  if (proType === '3_MONTHS') return 'Bản tiêu chuẩn'
  if (proType === '6_MONTHS') return 'Bản chuyên sâu'
  if (proType === '1_YEAR') return 'Bản toàn diện'
  const adminMatch = typeof proType === 'string' ? (proType as string).match(/^ADMIN_GRANTED_(\d+)M$/) : null
  if (adminMatch) return `ADMIN cấp ${adminMatch[1]} tháng`
  return 'Đã nâng cấp'
}

export default function Sidebar({ dbUser, collapsed = false, onToggle }: SidebarProps) {
  const pathname = usePathname()
  const [showLogout, setShowLogout] = useState(false)
  const isPro = dbUser?.isPro ?? false

  return (
    <>
      <div className="h-full flex flex-col bg-[#F5F0E8] border-r border-[#D6CFC4]">
        <div className={`flex items-center border-b border-[#D6CFC4] ${collapsed ? 'justify-center px-2 py-4' : 'gap-3 px-5 py-6'}`}>
          <div
            className="w-9 h-9 rounded-full overflow-hidden flex items-center justify-center flex-shrink-0"
            style={{ border: '1.5px solid #141414' }}
          >
            <img src="/logo.png" alt="Logo" className="w-full h-full object-cover" />
          </div>

          {!collapsed && (
            <div>
              <p className="text-[17px] font-serif font-black text-[#141414] leading-none">LinguaClay</p>
              <p className="mt-1 text-[10px] font-bold text-[#4B4B4B] uppercase" style={{ letterSpacing: '0.24em' }}>
                Học hiệu quả
              </p>
            </div>
          )}
        </div>

        <div className={`border-b border-[#D6CFC4] ${collapsed ? 'px-2 py-3' : 'px-4 py-3'}`}>
          <button
            onClick={onToggle}
            className={`w-full h-8 border border-[#D6CFC4] bg-transparent text-[#4B4B4B] hover:bg-white/50 hover:text-[#141414] transition-colors flex items-center ${
              collapsed ? 'justify-center' : 'justify-start gap-2 px-3'
            }`}
            title={collapsed ? 'Mở thanh điều hướng' : 'Thu thanh điều hướng'}
          >
            {collapsed ? <PanelLeftOpen size={14} /> : <PanelLeftClose size={14} />}
            {!collapsed && <span className="text-[10px] font-semibold uppercase tracking-[0.15em]">Thu gọn</span>}
          </button>
        </div>

        <nav className="flex-1 overflow-y-auto py-3" style={{ scrollbarWidth: 'none' }}>
          {menuItems.map(({ name, icon: Icon, path }) => {
            const active = path === '/dashboard' ? pathname === '/dashboard' : pathname.startsWith(path)
            return (
              <Link
                key={path}
                href={path}
                className={`relative flex items-center transition-all duration-300 group hover:bg-white/60 ${
                  collapsed ? 'justify-center px-3 py-3' : 'gap-3 px-5 py-3 hover:pl-7'
                }`}
                style={{
                  color: active ? '#141414' : '#4B4B4B',
                  background: active ? 'white' : 'transparent',
                }}
                title={collapsed ? name : undefined}
              >
                {active && (
                  <motion.span
                    layoutId="sidebar-bar"
                    className="absolute left-0 top-0 bottom-0 bg-red-600"
                    style={{ width: 3 }}
                    transition={{ type: 'spring', stiffness: 400, damping: 36 }}
                  />
                )}
                <Icon size={15} strokeWidth={active ? 2.5 : 1.75} className="flex-shrink-0" />
                {!collapsed && (
                  <span
                    className="uppercase"
                    style={{
                      fontSize: 12,
                      fontWeight: active ? 800 : 600,
                      letterSpacing: '0.17em',
                    }}
                  >
                    {name}
                  </span>
                )}
              </Link>
            )
          })}
        </nav>

        <div className={`pb-5 pt-4 border-t border-[#D6CFC4] space-y-2 ${collapsed ? 'px-2' : 'px-4'}`}>
          <Link
            href="/dashboard/plans"
            className={`block shadow-[4px_4px_0px_0px_rgba(20,20,20,1)] transition-all duration-300 hover:-translate-y-1 hover:shadow-[7px_7px_0px_0px_rgba(20,20,20,1)] group ${
              collapsed ? 'px-2 py-3' : 'px-4 py-3'
            }`}
            style={{
              border: '2px solid #141414',
              background: isPro ? '#FFFFFF' : 'rgba(255,255,255,0.45)',
            }}
            title={collapsed ? (isPro ? getPlanLabel(dbUser?.proType ?? null) : 'Hội viên') : undefined}
          >
            {collapsed ? (
              <div className="flex items-center justify-center text-[#141414]">
                <Crown size={15} />
              </div>
            ) : (
              <>
                <p className="uppercase font-black text-[#141414]" style={{ fontSize: 10, letterSpacing: '0.17em' }}>
                  {isPro ? 'Hội viên nâng cấp' : 'Hội viên'}
                </p>
                <p
                  className="uppercase font-semibold text-[#4B4B4B] group-hover:text-[#141414] transition-colors"
                  style={{ fontSize: 9, letterSpacing: '0.15em', marginTop: 2 }}
                >
                  {isPro ? getPlanLabel(dbUser?.proType ?? null) : 'Bản miễn phí'}
                </p>
              </>
            )}
          </Link>

          <button
            onClick={() => setShowLogout(true)}
            className={`w-full flex items-center transition-colors hover:text-red-600 text-[#141414]/40 group ${
              collapsed ? 'justify-center px-2 py-2' : 'gap-2 px-2 py-2'
            }`}
            title={collapsed ? 'Đăng xuất' : undefined}
          >
            <LogOut size={13} strokeWidth={2.5} className="group-hover:rotate-12 transition-transform" />
            {!collapsed && (
              <span style={{ fontSize: 10, letterSpacing: '0.17em', fontWeight: 700, textTransform: 'uppercase' }}>
                Đăng xuất
              </span>
            )}
          </button>
        </div>
      </div>

      <ConfirmDialog
        isOpen={showLogout}
        title="Đăng xuất"
        message="Bạn có chắc chắn muốn rời khỏi ứng dụng không?"
        onConfirm={async () => {
          setShowLogout(false)
          await signOut()
          if (typeof window !== 'undefined') window.location.replace('/')
        }}
        onCancel={() => setShowLogout(false)}
        confirmText="Đăng xuất"
        danger
      />
    </>
  )
}

'use client'

import React, { useState, useEffect } from 'react'
import { createClient } from '@/utils/supabase/client'
import { useRouter } from 'next/navigation'
import Link from 'next/link'
import { Eye, EyeOff, X, ArrowLeft, Check, Chrome } from 'lucide-react'
import { useAuth } from '@/providers/AuthProvider'

type Tab = 'signin' | 'signup' | 'forgotpassword'

interface AuthDrawerProps {
  isOpen: boolean
  onClose: () => void
  initialTab?: Tab
}

export default function AuthDrawer({ isOpen, onClose, initialTab = 'signin' }: AuthDrawerProps) {
  const [tab, setTab] = useState<Tab>(initialTab)
  const [fullName, setFullName] = useState('')
  const [email, setEmail] = useState('')
  const [password, setPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [rememberMe, setRememberMe] = useState(false)
  const [agreeToTerms, setAgreeToTerms] = useState(false)
  const [showPassword, setShowPassword] = useState(false)
  const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null)
  const [loading, setLoading] = useState(false)

  const supabase = createClient()
  const router = useRouter()
  const { redirectAfterLogin } = useAuth()

  // Reset state when tab changes
  useEffect(() => {
    setMessage(null)
  }, [tab])

  // Sync initialTab when props change
  useEffect(() => {
    setTab(initialTab)
  }, [initialTab, isOpen])

  const handleEmailAuth = async (e: React.FormEvent) => {
    e.preventDefault()
    setLoading(true)
    setMessage(null)

    if (tab === 'signup') {
      if (password !== confirmPassword) {
        setMessage({ type: 'error', text: 'Mật khẩu xác nhận không khớp.' })
        setLoading(false)
        return
      }
      if (!agreeToTerms) {
        setMessage({ type: 'error', text: 'Bạn cần đồng ý với điều khoản dịch vụ.' })
        setLoading(false)
        return
      }

      const { data, error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          data: { full_name: fullName },
          emailRedirectTo: `${window.location.origin}/api/auth/callback`,
        },
      })

      if (error) {
        if (error.message.includes('User already registered') || error.status === 400) {
          setMessage({ type: 'error', text: 'Tài khoản này đã tồn tại. Hãy đăng nhập ngay!' })
        } else {
          setMessage({ type: 'error', text: error.message })
        }
      } else {
        setMessage({ type: 'success', text: '🎉 Tài khoản đã tạo! Hãy kiểm tra email để xác nhận.' })
        setFullName('')
        setEmail('')
        setPassword('')
        setConfirmPassword('')
      }
    } else if (tab === 'signin') {
      const { data, error } = await supabase.auth.signInWithPassword({ email, password })
      if (error) {
        setMessage({ type: 'error', text: 'Email hoặc mật khẩu không đúng.' })
      } else {
        await fetch('/api/auth/sync-user', { method: 'POST' })
        onClose()
        router.push(redirectAfterLogin || '/dashboard')
        router.refresh()
      }
    } else if (tab === 'forgotpassword') {
      const { error } = await supabase.auth.resetPasswordForEmail(email, {
        redirectTo: `${window.location.origin}/api/auth/callback?next=/dashboard/settings`,
      })
      if (error) {
        setMessage({ type: 'error', text: error.message })
      } else {
        setMessage({ type: 'success', text: '✉️ Link đặt lại mật khẩu đã được gửi vào email của bạn.' })
      }
    }
    setLoading(false)
  }

  const handleGoogleLogin = async () => {
    setLoading(true)
    setMessage(null)
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo: `${window.location.origin}/api/auth/callback?next=${encodeURIComponent(redirectAfterLogin || '/dashboard')}`,
        queryParams: { access_type: 'offline', prompt: 'consent' },
      },
    })
    if (error) {
      setMessage({ type: 'error', text: error.message })
      setLoading(false)
    }
  }

  return (
    <>
      {/* Overlay */}
      <div 
        className={`fixed inset-0 bg-newsprint-black/40 backdrop-blur-sm z-[100] transition-opacity duration-500 ${isOpen ? 'opacity-100 pointer-events-auto' : 'opacity-0 pointer-events-none'}`}
        onClick={onClose}
      />

      {/* Drawer */}
      <div 
        className={`fixed top-0 right-0 h-full w-full sm:w-[400px] bg-[#F5F0E8] border-l-[3px] border-newsprint-black z-[101] shadow-[-10px_0px_30px_rgba(0,0,0,0.1)] transition-transform duration-500 transform ${isOpen ? 'translate-x-0' : 'translate-x-full'} flex flex-col`}
      >
        {/* Header */}
        <div className="p-6 border-b-[3px] border-newsprint-black flex items-center justify-between bg-[#F5F0E8] sticky top-0 z-20">
           <h2 className="text-xl font-serif font-black uppercase tracking-tight text-newsprint-black">
              {tab === 'signin' ? 'Đăng nhập' : tab === 'signup' ? 'Tạo tài khoản' : 'Quên mật khẩu'}
           </h2>
           <button 
              onClick={onClose}
              className="text-newsprint-black hover:text-red-600 transition-colors p-1"
           >
              <X size={24} className="stroke-[3px]" />
           </button>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-6 sm:p-8 custom-scrollbar">
           {tab !== 'forgotpassword' && (
             /* Tab Switch */
             <div className="flex border-[2px] border-newsprint-black mb-8 overflow-hidden bg-white shadow-[4px_4px_0px_0px_rgba(20,20,20,1)]">
                <button 
                   onClick={() => setTab('signin')}
                   className={`flex-1 py-3 font-sans font-black uppercase tracking-[0.1em] text-[10px] transition-all duration-200 ${tab === 'signin' ? 'bg-black text-white' : 'bg-white text-black hover:bg-[#F5F0E8]'}`}
                >
                   Đăng nhập
                </button>
                <button 
                   onClick={() => setTab('signup')}
                   className={`flex-1 py-3 font-sans font-black uppercase tracking-[0.1em] text-[10px] transition-all duration-200 border-l-[2px] border-newsprint-black ${tab === 'signup' ? 'bg-black text-white' : 'bg-white text-black hover:bg-[#F5F0E8]'}`}
                >
                   Đăng ký
                </button>
             </div>
           )}

           {tab === 'forgotpassword' && (
             <p className="font-sans text-[11px] font-bold text-newsprint-gray-dark uppercase tracking-widest mb-8 leading-relaxed">
                Nhập email của bạn, chúng tôi sẽ gửi link đặt lại mật khẩu.
             </p>
           )}

           <form onSubmit={handleEmailAuth} className="space-y-6">
              {tab === 'signup' && (
                <div className="space-y-2">
                  <label className="block font-sans font-bold text-[10px] uppercase tracking-widest text-newsprint-black ml-1">Họ tên</label>
                  <input
                    type="text"
                    value={fullName}
                    onChange={(e) => setFullName(e.target.value)}
                    placeholder="Nguyễn Văn A"
                    required
                    className="w-full px-5 py-3 border-[2px] border-newsprint-black bg-white font-sans text-sm text-newsprint-black focus:outline-none transition-all"
                    disabled={loading}
                  />
                </div>
              )}

              <div className="space-y-2">
                <label className="block font-sans font-bold text-[10px] uppercase tracking-widest text-newsprint-black ml-1">Địa chỉ Email</label>
                <input
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="example@gmail.com"
                  required
                  className="w-full px-5 py-3 border-[2px] border-newsprint-black bg-white font-sans text-sm text-newsprint-black focus:outline-none transition-all"
                  disabled={loading}
                />
              </div>

              {tab !== 'forgotpassword' && (
                <div className="space-y-2">
                  <label className="block font-sans font-bold text-[10px] uppercase tracking-widest text-newsprint-black ml-1">Mật khẩu</label>
                  <div className="relative">
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      placeholder="••••••••"
                      required
                      minLength={6}
                      className="w-full px-5 py-3 border-[2px] border-newsprint-black bg-white font-sans text-sm text-newsprint-black focus:outline-none transition-all"
                      disabled={loading}
                    />
                    <button
                      type="button"
                      onClick={() => setShowPassword(!showPassword)}
                      className="absolute right-4 top-1/2 -translate-y-1/2 text-newsprint-gray-dark hover:text-newsprint-black transition-colors"
                    >
                      {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                    </button>
                  </div>

                  {tab === 'signin' && (
                    <div className="flex items-center justify-between mt-1 px-1">
                      <div className="flex items-center gap-2">
                        <input 
                          type="checkbox" 
                          id="remember-me" 
                          checked={rememberMe}
                          onChange={(e) => setRememberMe(e.target.checked)}
                          className="w-4 h-4 border-2 border-newsprint-black accent-black cursor-pointer"
                        />
                        <label htmlFor="remember-me" className="font-sans text-[10px] font-bold uppercase tracking-widest text-newsprint-gray-dark cursor-pointer select-none">
                          Ghi nhớ đăng nhập
                        </label>
                      </div>
                      <button 
                        type="button"
                        onClick={() => setTab('forgotpassword')}
                        className="font-sans text-[10px] font-bold uppercase tracking-widest text-newsprint-gray-dark hover:text-red-600 transition-colors underline"
                      >
                         Quên mật khẩu?
                      </button>
                    </div>
                  )}
                </div>
              )}

              {tab === 'signup' && (
                <>
                  <div className="space-y-2">
                    <label className="block font-sans font-bold text-[10px] uppercase tracking-widest text-newsprint-black ml-1">Xác nhận mật khẩu</label>
                    <input
                      type={showPassword ? 'text' : 'password'}
                      value={confirmPassword}
                      onChange={(e) => setConfirmPassword(e.target.value)}
                      placeholder="••••••••"
                      required
                      className="w-full px-5 py-4 border-[3px] border-newsprint-black bg-white font-sans text-sm text-newsprint-black focus:outline-none focus:ring-4 focus:ring-newsprint-black/5 transition-all"
                      disabled={loading}
                    />
                  </div>
                  <div className="flex items-start gap-4 py-2">
                    <input
                      type="checkbox"
                      id="agree-drawer"
                      checked={agreeToTerms}
                      onChange={(e) => setAgreeToTerms(e.target.checked)}
                      className="mt-1 w-5 h-5 border-[3px] border-newsprint-black checked:bg-newsprint-black transition-all cursor-pointer accent-black shrink-0"
                    />
                    <label htmlFor="agree-drawer" className="text-[11px] font-sans text-newsprint-gray-dark leading-relaxed cursor-pointer font-medium">
                       Tôi đã đọc và đồng ý với <Link href="/support/terms" className="text-newsprint-black font-bold underline">Điều khoản dịch vụ</Link> và <Link href="/support/privacy" className="text-newsprint-black font-bold underline">Chính sách bảo mật</Link>.
                    </label>
                  </div>
                </>
              )}

              {message && (
                <div className={`p-4 border-[3px] font-sans font-bold text-[10px] uppercase tracking-widest text-center ${message.type === 'success' ? 'bg-[#3A7642]/10 border-[#3A7642] text-[#3A7642]' : 'bg-red-600/5 border-red-600 text-red-600'}`}>
                   {message.text}
                </div>
              )}

              <button
                type="submit"
                disabled={loading}
                className="w-full py-5 bg-black text-white font-sans font-black uppercase tracking-[0.1em] text-xs border-[3px] border-black hover:bg-[#F5F0E8] hover:text-black transition-all duration-300 shadow-[6px_6px_0px_0px_rgba(20,20,20,1)] hover:shadow-[2px_2px_0px_0px_rgba(20,20,20,1)] hover:translate-x-[4px] hover:translate-y-[4px] disabled:opacity-50"
              >
                {loading ? 'Đang xử lý...' : (tab === 'signin' ? 'Đăng nhập ngay' : tab === 'signup' ? 'Tạo tài khoản miễn phí' : 'Gửi link đặt lại')}
