import pino from 'pino';

const pinoLogger = pino({
  level: process.env.NODE_ENV === 'production' ? 'info' : 'debug',
  ...(process.env.NODE_ENV !== 'production' && {
    transport: {
      target: 'pino-pretty',
      options: {
        colorize: true,
      },
    },
  }),
});

export const logger = {
  info: (...args: any[]) => {
    if (typeof args[0] === 'string' && args.length > 1) {
      const [msg, ...rest] = args;
      pinoLogger.info({ data: rest.length === 1 ? rest[0] : rest }, msg);
    } else {
      // @ts-ignore
      pinoLogger.info(...args);
    }
  },
  error: (...args: any[]) => {
    if (typeof args[0] === 'string' && args.length > 1) {
      const [msg, err, ...rest] = args;
      pinoLogger.error(err instanceof Error ? err : { err, ...rest }, msg);
    } else {
      // @ts-ignore
      pinoLogger.error(...args);
    }
  },
  warn: (...args: any[]) => {
    // @ts-ignore
    pinoLogger.warn(...args);
  },
  debug: (...args: any[]) => {
    // @ts-ignore
    pinoLogger.debug(...args);
  },
};

'use client'

import React, { createContext, useContext, useState, useEffect } from 'react'

type AuthTab = 'signin' | 'signup'

interface AuthContextType {
  isAuthOpen: boolean
  authTab: AuthTab
  redirectAfterLogin: string
  openAuth: (tab?: AuthTab, redirectTo?: string) => void
  closeAuth: () => void
}

const AuthContext = createContext<AuthContextType | undefined>(undefined)

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [isAuthOpen, setIsAuthOpen] = useState(false)
  const [authTab, setAuthTab] = useState<AuthTab>('signin')
  const [redirectAfterLogin, setRedirectAfterLogin] = useState('/dashboard')

  useEffect(() => {
    if (typeof window !== 'undefined') {
      const urlParams = new URLSearchParams(window.location.search)
      if (urlParams.get('login') === 'true') {
        setIsAuthOpen(true)
        setAuthTab('signin')
        urlParams.delete('login')
        const newUrl = window.location.pathname + (urlParams.toString() ? `?${urlParams.toString()}` : '') + window.location.hash
        window.history.replaceState({}, '', newUrl || '/')
      }
    }
  }, [])

  const openAuth = (tab: AuthTab = 'signin', redirectTo = '/dashboard') => {
    setAuthTab(tab)
    setRedirectAfterLogin(redirectTo)
    setIsAuthOpen(true)
  }

  const closeAuth = () => {
    setIsAuthOpen(false)
  }

  return (
    <AuthContext.Provider value={{ isAuthOpen, authTab, redirectAfterLogin, openAuth, closeAuth }}>
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return context
}

const fs = require('fs');
const path = require('path');

function walk(dir) {
  let results = [];
  const list = fs.readdirSync(dir);
  list.forEach(function(file) {
    file = path.join(dir, file);
    const stat = fs.statSync(file);
    if (stat && stat.isDirectory()) { 
      results = results.concat(walk(file));
    } else { 
      results.push(file);
    }
  });
  return results;
}

